 1	import * as React from 'react';
 2	import classnames from 'classnames';
 3	
 4	import { V1GPU, V1HostDevice } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { DescriptionList, Stack, StackItem } from '@patternfly/react-core';
 7	
 8	import VirtualMachineDescriptionItem from '../VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 9	
10	import './hardware-devices-table.scss';
11	
12	type HardwareDevicesTableProps = {
13	  devices: V1GPU[] | V1HostDevice[];
14	};
15	
16	const HardwareDevicesTable: React.FC<HardwareDevicesTableProps> = ({ devices }) => {
17	  const { t } = useKubevirtTranslation();
18	
19	  if (!devices?.length) return <span className="text-muted">{t('Not available')}</span>;
20	
21	  return (
22	    <DescriptionList
23	      className={classnames('pf-v6-c-description-list', 'hardware-devices-table')}
24	      columnModifier={{ default: '2Col' }}
25	    >
26	      <VirtualMachineDescriptionItem
27	        descriptionData={
28	          <Stack>
29	            {devices.map((device: { deviceName: string; index: number; name: string }) => (
30	              <StackItem key={`${device?.name}-${device?.deviceName}`}>
31	                {device.deviceName}
32	              </StackItem>
33	            ))}
34	          </Stack>
35	        }
36	        descriptionHeader={t('Name')}
37	      />
38	      <VirtualMachineDescriptionItem
39	        descriptionData={
40	          <Stack>
41	            {devices.map((device) => (
42	              <StackItem key={device.name}>{device.name}</StackItem>
43	            ))}
44	          </Stack>
45	        }
46	        descriptionHeader={t('Device name')}
47	      />
48	    </DescriptionList>
49	  );
50	};
51	
52	export default HardwareDevicesTable;

